"use client"

import { useState, useEffect, useMemo } from 'react'
import { Activity, LayoutDashboard, FileCheck, Ticket, CalendarClock, LogOut, Sun, Moon, Clock, LogIn, UserPlus } from 'lucide-react'
import Link from 'next/link'
import { usePathname, useRouter } from 'next/navigation'
import { useAuth } from '../context/AuthContext'

function seededRandom(seed) {
  let s = seed
  return () => {
    s = (s * 16807 + 0) % 2147483647
    return (s - 1) / 2147483646
  }
}

function SpaceBackground() {
  const stars = useMemo(() => {
    const rng = seededRandom(42)
    return Array.from({ length: 80 }, (_, i) => ({
      id: i,
      left: `${rng() * 100}%`,
      top: `${rng() * 100}%`,
      size: `${rng() * 2 + 1}px`,
      duration: `${rng() * 4 + 2}s`,
      delay: `${rng() * 5}s`,
    }))
  }, [])

  const meteors = useMemo(() => {
    const rng = seededRandom(99)
    return Array.from({ length: 4 }, (_, i) => ({
      id: i,
      left: `${rng() * 80 + 10}%`,
      top: `${rng() * 30}%`,
      duration: `${rng() * 4 + 6}s`,
      delay: `${i * 3 + rng() * 2}s`,
    }))
  }, [])

  return (
    <div className="space-bg">
      {stars.map(star => (
        <div
          key={`star-${star.id}`}
          className="star"
          style={{
            left: star.left,
            top: star.top,
            width: star.size,
            height: star.size,
            '--duration': star.duration,
            animationDelay: star.delay,
          }}
        />
      ))}
      {meteors.map(meteor => (
        <div
          key={`meteor-${meteor.id}`}
          className="meteor"
          style={{
            left: meteor.left,
            top: meteor.top,
            '--duration': meteor.duration,
            animationDelay: meteor.delay,
          }}
        />
      ))}
      <div
        className="nebula"
        style={{
          width: '400px',
          height: '400px',
          top: '20%',
          right: '10%',
          background: 'radial-gradient(circle, rgba(99, 102, 241, 0.3), transparent)',
        }}
      />
      <div
        className="nebula"
        style={{
          width: '300px',
          height: '300px',
          bottom: '15%',
          left: '20%',
          background: 'radial-gradient(circle, rgba(56, 189, 248, 0.2), transparent)',
          animationDelay: '10s',
        }}
      />
    </div>
  )
}

export default function Layout({ children }) {
  const pathname = usePathname()
  const router = useRouter()
  const [isDark, setIsDark] = useState(false)
  const [mounted, setMounted] = useState(false)
  const { user, logout, loading } = useAuth()

  useEffect(() => {
    setMounted(true)
    const saved = localStorage.getItem('smartgov-theme')
    if (saved === 'dark') {
      setIsDark(true)
      document.documentElement.setAttribute('data-theme', 'dark')
    }
  }, [])

  const toggleTheme = () => {
    const next = !isDark
    setIsDark(next)
    if (next) {
      document.documentElement.setAttribute('data-theme', 'dark')
      localStorage.setItem('smartgov-theme', 'dark')
    } else {
      document.documentElement.removeAttribute('data-theme')
      localStorage.setItem('smartgov-theme', 'light')
    }
  }

  // RBAC Configuration
  const allTabs = [
    { id: 'dashboard', label: 'Monitor Dashboard', icon: LayoutDashboard, href: '/', roles: ['Citizen', 'Employee', 'Admin'] },
    { id: 'document', label: 'AI Doc Verification', icon: FileCheck, href: '/document', roles: ['Citizen', 'Employee', 'Admin'] },
    { id: 'token', label: 'Smart Token System', icon: Ticket, href: '/token', roles: ['Citizen', 'Admin'] },
    { id: 'officer', label: 'Officer Scheduling', icon: CalendarClock, href: '/officer', roles: ['Employee', 'Admin'] },
  ]

  const isAuthPage = pathname === '/login' || pathname === '/register'
  const tabs = allTabs.filter(tab => !user || tab.roles.includes(user.role))
  const activeTabObj = tabs.find(t => t.href === pathname) || tabs[0]
  
  if (loading) return <div className="app-container"><SpaceBackground /></div>

  return (
    <div className="app-container">
      <SpaceBackground />

      {!isAuthPage && (
        <aside className="sidebar">
          <div className="logo-container">
            <div className="logo-icon">
              <Activity size={20} />
            </div>
            <h2 style={{fontSize: '1.25rem', marginBottom: 0}}>SmartGov</h2>
          </div>

          <nav className="nav-links" style={{flex: 1}}>
            {tabs.map(tab => {
              const Icon = tab.icon
              const isActive = pathname === tab.href
              return (
                <Link
                  key={tab.id}
                  href={tab.href}
                  className={`nav-item ${isActive ? 'active' : ''}`}
                  style={{textDecoration: 'none'}}
                >
                  <Icon size={18} />
                  <span>{tab.label}</span>
                </Link>
              )
            })}
          </nav>

          {user ? (
            <div className="nav-item" style={{color: 'var(--danger)', marginTop: 'auto'}} onClick={logout}>
              <LogOut size={18} />
              <span>Sign Out</span>
            </div>
          ) : (
            <div style={{marginTop: 'auto', display: 'flex', flexDirection: 'column', gap: '8px'}}>
              <Link href="/login" className="btn btn-outline" style={{width: '100%'}}>
                <LogIn size={16} style={{marginRight: '8px'}} /> Login
              </Link>
              <Link href="/register" className="btn btn-primary" style={{width: '100%'}}>
                <UserPlus size={16} style={{marginRight: '8px'}} /> Register
              </Link>
            </div>
          )}
        </aside>
      )}

      <main className="main-content" style={isAuthPage ? { alignItems: 'center', justifyContent: 'center' } : {}}>
        {!isAuthPage && (
          <header style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem'}}>
            <div>
              <h1 className="animate-fade-in" style={{marginBottom: '0.25rem'}}>
                {activeTabObj?.label || 'Dashboard'}
              </h1>
              <p className="animate-fade-in" style={{animationDelay: '0.1s'}}>
                Manage your services dynamically and beat the crowd.
              </p>
            </div>
            <div style={{display: 'flex', gap: '1rem', alignItems: 'center'}}>
              {mounted && (
                <button
                  className="theme-toggle-btn"
                  onClick={toggleTheme}
                  aria-label="Toggle theme"
                >
                  {isDark ? <Sun size={18} /> : <Moon size={18} />}
                </button>
              )}
              <div className="badge badge-info text-sm" style={{display: 'flex', alignItems: 'center', gap: '6px'}}>
                <Clock size={14} />
                Office Hours: 10 AM – 5 PM
              </div>
              {user && (
                <div className="glass-panel" style={{padding: '0.5rem 1rem', borderRadius: '9999px', fontSize: '0.875rem', fontWeight: 500, display: 'flex', alignItems: 'center', gap: '8px'}}>
                  <span style={{color: 'var(--primary)'}}>{user.name}</span>
                  <div className={`badge ${user.role === 'Admin' ? 'badge-danger' : user.role === 'Employee' ? 'badge-warning' : 'badge-success'}`}>
                    {user.role}
                  </div>
                </div>
              )}
            </div>
          </header>
        )}

        <div className="animate-fade-in" style={{animationDelay: '0.2s', flex: 1}}>
          {children}
        </div>
      </main>
    </div>
  )
}
